import React, { useEffect, useState } from 'react';

function ModeratorDashboard() {
  const [users, setUsers] = useState([]);
  const [editIndex, setEditIndex] = useState(null);
  const [editedData, setEditedData] = useState({ username: '', email: '', role: '' });

  useEffect(() => {
    fetch('http://localhost:8000/api/moderator/users/', {
      headers: {
        Authorization: `Bearer ${localStorage.getItem('accessToken')}`,
      },
    })
      .then((res) => res.json())
      .then((data) => setUsers(data))
      .catch((err) => console.error(err));
  }, []);

  const handleDelete = (id) => {
    fetch(`http://localhost:8000/api/moderator/users/${id}/`, {
      method: 'DELETE',
      headers: {
        Authorization: `Bearer ${localStorage.getItem('accessToken')}`,
      },
    })
      .then(() => setUsers(users.filter((user) => user.id !== id)))
      .catch((err) => console.error(err));
  };

  const handleEdit = (index) => {
    setEditIndex(index);
    setEditedData({
      username: users[index].username,
      email: users[index].email,
      role: users[index].role,
    });
  };

  const handleSave = (id) => {
    fetch(`http://localhost:8000/api/moderator/users/${id}/`, {
      method: 'PUT',
      headers: {
        'Content-Type': 'application/json',
        Authorization: `Bearer ${localStorage.getItem('accessToken')}`,
      },
      body: JSON.stringify({
        username: editedData.username,
        email: editedData.email,
        role: editedData.role,
      }),
    })
      .then((res) => res.json())
      .then((updatedUser) => {
        const updatedUsers = [...users];
        updatedUsers[editIndex] = updatedUser;
        setUsers(updatedUsers);
        setEditIndex(null);
      })
      .catch((err) => console.error(err));
  };

  const handleChange = (e) => {
    setEditedData({ ...editedData, [e.target.name]: e.target.value });
  };

  return (
    <div style={{ padding: '20px', textAlign: 'center' }}>
      <h2>Moderator Dashboard</h2>
      <table style={{ margin: '0 auto', borderCollapse: 'collapse', width: '90%' }}>
        <thead>
          <tr>
            <th>ID</th>
            <th>Username</th>
            <th>Email</th>
            <th>Role</th>
            <th>Actions</th>
          </tr>
        </thead>
        <tbody>
          {users.map((user, index) => (
            <tr key={user.id}>
              <td>{user.id}</td>
              <td>
                {editIndex === index ? (
                  <input
                    type="text"
                    name="username"
                    value={editedData.username}
                    onChange={handleChange}
                  />
                ) : (
                  user.username
                )}
              </td>
              <td>
                {editIndex === index ? (
                  <input
                    type="email"
                    name="email"
                    value={editedData.email}
                    onChange={handleChange}
                  />
                ) : (
                  user.email
                )}
              </td>
              <td>
                {editIndex === index ? (
                  <input
                    type="text"
                    name="role"
                    value={editedData.role}
                    onChange={handleChange}
                  />
                ) : (
                  user.role
                )}
              </td>
              <td>
                {editIndex === index ? (
                  <button onClick={() => handleSave(user.id)}>Save</button>
                ) : (
                  <button onClick={() => handleEdit(index)}>Edit</button>
                )}
                <button onClick={() => handleDelete(user.id)} style={{ marginLeft: '10px' }}>
                  Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default ModeratorDashboard;
